  ffi.Pointer<ffi.Char> key,
  ffi.Pointer<kvWatchOptions> opts,
);

natsStatus kvStore_History(
  ffi.Pointer<kvEntryList> list,
  ffi.Pointer<kvStore> kv,
  ffi.Pointer<ffi.Char> key,
  ffi.Pointer<kvWatchOptions> opts,
) =>
    natsStatus.fromValue(_kvStore_History(
      list,
      kv,
      key,
      opts,
    ));

/// \brief Destroys this list of KeyValue store entries.
///
/// This function iterates through the list of all entries and call #kvEntry_Destroy.
/// It then frees the array that was allocated to hold pointers to those entries.
///
/// \note The #kvEntryList object itself is not freed since it is expected that
/// users will pass a pointer to a stack object. Should the user create its own
/// object, it will be the user responsibility to free this object.
///
/// @param list the #kvEntryList list of #kvEntry objects to destroy.
@ffi.Native<ffi.Void Function(ffi.Pointer<kvEntryList>)>()
external void kvEntryList_Destroy(
  ffi.Pointer<kvEntryList> list,
);

/// \brief Returns the bucket name of this KeyValue store object.
///
/// Returns the bucket name of this KeyValue store object, or `NULL` if
/// `kv` itself is NULL.
///
/// \warning Do not free the string returned by this function.
///
/// @param kv the pointer to the #kvStore object.
@ffi.Native<ffi.Pointer<ffi.Char> Function(ffi.Pointer<kvStore>)>()
external ffi.Pointer<ffi.Char> kvStore_Bucket(
  ffi.Pointer<kvStore> kv,
);

/// \brief Returns the next entry for this watcher.
///
/// Returns the next entry for this watcher. The entry may be `NULL`
/// (with #NATS_OK status) to indicate that the initial state has
/// been retrieved.
///
/// If a thread is waiting on this call, it can be canceled with a call to
/// #kvWatcher_Stop.
///
/// \note The entry should be destroyed to release memory using #kvEntry_Destroy.
///
/// @param new_entry the location where to store the pointer to the #kvEntry object.
/// @param w the pointer to the #kvWatcher object.
/// @param timeout how long to wait (in milliseconds) for the next entry.
@ffi.Native<
    ffi.UnsignedInt Function(ffi.Pointer<ffi.Pointer<kvEntry>>,
        ffi.Pointer<kvWatcher>, ffi.Int64)>(symbol: 'kvWatcher_Next')
external int _kvWatcher_Next(
  ffi.Pointer<ffi.Pointer<kvEntry>> new_entry,
  ffi.Pointer<kvWatcher> w,
  int timeout,
);

natsStatus kvWatcher_Next(
  ffi.Pointer<ffi.Pointer<kvEntry>> new_entry,
  ffi.Pointer<kvWatcher> w,
  int timeout,
) =>
    natsStatus.fromValue(_kvWatcher_Next(
      new_entry,
      w,
      timeout,
    ));

/// \brief Stops the watcher.
///
/// Stops the watcher. Stopping a stopped watcher returns #NATS_OK.
///
/// After this call, new and existing calls to #kvWatcher_Next (that are waiting
/// for an update) will return with #NATS_ILLEGAL_STATE.
///
/// @param w the pointer to the #kvWatcher object.
@ffi.Native<ffi.UnsignedInt Function(ffi.Pointer<kvWatcher>)>(
    symbol: 'kvWatcher_Stop')
external int _kvWatcher_Stop(
  ffi.Pointer<kvWatcher> w,
);

natsStatus kvWatcher_Stop(
  ffi.Pointer<kvWatcher> w,
) =>
    natsStatus.fromValue(_kvWatcher_Stop(
      w,
    ));

/// \brief Destroys the KeyValue watcher object.
///
/// Releases memory allocated for this #kvWatcher object.
///
/// @param w the pointer to the #kvWatcher object.
@ffi.Native<ffi.Void Function(ffi.Pointer<kvWatcher>)>()
external void kvWatcher_Destroy(
  ffi.Pointer<kvWatcher> w,
);

/// The connection state
enum natsConnStatus {
  /// < The connection has been disconnected
  NATS_CONN_STATUS_DISCONNECTED(0),

  /// < The connection is in the process or connecting
  NATS_CONN_STATUS_CONNECTING(1),

  /// < The connection is connected
  NATS_CONN_STATUS_CONNECTED(2),

  /// < The connection is closed
  NATS_CONN_STATUS_CLOSED(3),

  /// < The connection is in the process or reconnecting
  NATS_CONN_STATUS_RECONNECTING(4),

  /// < The connection is draining subscriptions
  NATS_CONN_STATUS_DRAINING_SUBS(5),

  /// < The connection is draining publishers
  NATS_CONN_STATUS_DRAINING_PUBS(6);

  final int value;
  const natsConnStatus(this.value);

  static natsConnStatus fromValue(int value) => switch (value) {
        0 => NATS_CONN_STATUS_DISCONNECTED,
        1 => NATS_CONN_STATUS_CONNECTING,
        2 => NATS_CONN_STATUS_CONNECTED,
        3 => NATS_CONN_STATUS_CLOSED,
        4 => NATS_CONN_STATUS_RECONNECTING,
        5 => NATS_CONN_STATUS_DRAINING_SUBS,
        6 => NATS_CONN_STATUS_DRAINING_PUBS,
        _ => throw ArgumentError('Unknown value for natsConnStatus: $value'),
      };
}

/// Status returned by most of the APIs
enum natsStatus {
  /// < Success
  NATS_OK(0),

  /// < Generic error
  NATS_ERR(1),

  /// < Error when parsing a protocol message,
  NATS_PROTOCOL_ERROR(2),

  /// < IO Error (network communication).
  NATS_IO_ERROR(3),

  /// < The protocol message read from the socket
  NATS_LINE_TOO_LONG(4),

  /// < Operation on this connection failed because
  NATS_CONNECTION_CLOSED(5),

  /// < Unable to connect, the server could not be
  NATS_NO_SERVER(6),

  /// < The server closed our connection because it
  NATS_STALE_CONNECTION(7),

  /// < The client is configured to use TLS, but the
  NATS_SECURE_CONNECTION_WANTED(8),

  /// < The server expects a TLS connection.
  NATS_SECURE_CONNECTION_REQUIRED(9),

  /// < The connection was disconnected. Depending on
  NATS_CONNECTION_DISCONNECTED(10),

  /// < The connection failed due to authentication error.
  NATS_CONNECTION_AUTH_FAILED(11),

  /// < The action is not permitted.
  NATS_NOT_PERMITTED(12),

  /// < An action could not complete because something
  NATS_NOT_FOUND(13),

  /// < Incorrect URL. For instance no host specified in
  NATS_ADDRESS_MISSING(14),

  /// < Invalid subject, for instance NULL or empty string.
  NATS_INVALID_SUBJECT(15),

  /// < An invalid argument is passed to a function. For
  NATS_INVALID_ARG(16),

  /// < The call to a subscription function fails because
  NATS_INVALID_SUBSCRIPTION(17),

  /// < Timeout must be positive numbers.
  NATS_INVALID_TIMEOUT(18),

  /// < An unexpected state, for instance calling
  NATS_ILLEGAL_STATE(19),

  /// < The maximum number of messages waiting to be
  NATS_SLOW_CONSUMER(20),

  /// < Attempt to send a payload larger than the maximum
  NATS_MAX_PAYLOAD(21),

  /// < Attempt to receive more messages than allowed, for
  NATS_MAX_DELIVERED_MSGS(22),

  /// < A buffer is not large enough to accommodate the data.
  NATS_INSUFFICIENT_BUFFER(23),

  /// < An operation could not complete because of insufficient
  NATS_NO_MEMORY(24),

  /// < Some system function returned an error.
  NATS_SYS_ERROR(25),

  /// < An operation timed-out. For instance
  NATS_TIMEOUT(26),

  /// < The library failed to initialize.
  NATS_FAILED_TO_INITIALIZE(27),

  /// < The library is not yet initialized.
  NATS_NOT_INITIALIZED(28),

  /// < An SSL error occurred when trying to establish a
  NATS_SSL_ERROR(29),

  /// < The server does not support this action.
  NATS_NO_SERVER_SUPPORT(30),

  /// < A connection could not be immediately established and
  NATS_NOT_YET_CONNECTED(31),

  /// < A connection and/or subscription entered the draining mode.
  NATS_DRAINING(32),

  /// < An invalid queue name was passed when creating a queue subscription.
  NATS_INVALID_QUEUE_NAME(33),

  /// < No responders were running when the server received the request.
  NATS_NO_RESPONDERS(34),

  /// < For JetStream subscriptions, it means that a consumer sequence mismatch was discovered.
  NATS_MISMATCH(35),

  /// < For JetStream subscriptions, it means that the library detected that server heartbeats have been missed.
  NATS_MISSED_HEARTBEAT(36),

  /// < Attempt to receive messages than allowed by the byte limit, for
  NATS_LIMIT_REACHED(37),

  /// < Pin ID sent in the request does not match the currently pinned
  NATS_PIN_ID_MISMATCH(38),

  /// < Maximum status value, this element MUST be the last one
  NATS_MAX_STATUS_VALUE(39);

  final int value;
  const natsStatus(this.value);

  static natsStatus fromValue(int value) => switch (value) {
        0 => NATS_OK,
        1 => NATS_ERR,
        2 => NATS_PROTOCOL_ERROR,
        3 => NATS_IO_ERROR,
        4 => NATS_LINE_TOO_LONG,
        5 => NATS_CONNECTION_CLOSED,
        6 => NATS_NO_SERVER,
        7 => NATS_STALE_CONNECTION,
        8 => NATS_SECURE_CONNECTION_WANTED,
        9 => NATS_SECURE_CONNECTION_REQUIRED,
        10 => NATS_CONNECTION_DISCONNECTED,
        11 => NATS_CONNECTION_AUTH_FAILED,
        12 => NATS_NOT_PERMITTED,
        13 => NATS_NOT_FOUND,
        14 => NATS_ADDRESS_MISSING,
        15 => NATS_INVALID_SUBJECT,
        16 => NATS_INVALID_ARG,
        17 => NATS_INVALID_SUBSCRIPTION,
        18 => NATS_INVALID_TIMEOUT,
        19 => NATS_ILLEGAL_STATE,
        20 => NATS_SLOW_CONSUMER,
        21 => NATS_MAX_PAYLOAD,
        22 => NATS_MAX_DELIVERED_MSGS,
        23 => NATS_INSUFFICIENT_BUFFER,
        24 => NATS_NO_MEMORY,
        25 => NATS_SYS_ERROR,
        26 => NATS_TIMEOUT,
        27 => NATS_FAILED_TO_INITIALIZE,
        28 => NATS_NOT_INITIALIZED,
        29 => NATS_SSL_ERROR,
        30 => NATS_NO_SERVER_SUPPORT,
        31 => NATS_NOT_YET_CONNECTED,
        32 => NATS_DRAINING,
        33 => NATS_INVALID_QUEUE_NAME,
        34 => NATS_NO_RESPONDERS,
        35 => NATS_MISMATCH,
        36 => NATS_MISSED_HEARTBEAT,
        37 => NATS_LIMIT_REACHED,
        38 => NATS_PIN_ID_MISMATCH,
        39 => NATS_MAX_STATUS_VALUE,
        _ => throw ArgumentError('Unknown value for natsStatus: $value'),
      };
}

