final class __natsConnection extends ffi.Opaque {}

/// \brief A connection to a `NATS Server`.
///
/// A #natsConnection represents a bare connection to a `NATS Server`. It will
/// send and receive byte array payloads.
typedef natsConnection = __natsConnection;

final class __natsSubscription extends ffi.Opaque {}

/// \brief Interest on a given subject.
///
/// A #natsSubscription represents interest in a given subject.
typedef natsSubscription = __natsSubscription;

final class __natsMsg extends ffi.Opaque {}

/// \brief A structure holding a subject, optional reply and payload.
///
/// #natsMsg is a structure used by Subscribers and
/// #natsConnection_PublishMsg().
typedef natsMsg = __natsMsg;

final class __natsOptions extends ffi.Opaque {}

/// \brief Way to configure a #natsConnection.
///
/// Options can be used to create a customized #natsConnection.
typedef natsOptions = __natsOptions;

/// \brief A list of NATS messages.
///
/// Used by some APIs which return a list of #natsMsg objects.
///
/// Those APIs will not create the object, but instead initialize
/// the object to which a pointer to that object will be passed to it.
/// Typically, the user will define the object on the stack and
/// pass a pointer to this object to APIs that require a pointer
/// to a #natsMsgList object.
///
/// Similarly, calling #natsMsgList_Destroy will call #natsMsg_Destroy
/// on any message still in the list, free the array containing pointers
/// to the messages, but not free the #natsMsgList object itself.
///
/// \note If the user wants to keep some of the messages from the
/// list, the pointers of those messages in the `Msgs` array should
/// be set to `NULL`. The value `Count` MUST not be changed. The
/// function #natsMsgList_Destroy will iterate through all
/// pointers in the list and only destroy the ones that have not
/// been set to `NULL`.
///
/// @see natsMsgList_Destroy
final class natsMsgList extends ffi.Struct {
  external ffi.Pointer<ffi.Pointer<natsMsg>> Msgs;

  @ffi.Int()
  external int Count;
}

/// \brief A type to represent user-provided metadata, a list of k=v pairs.
///
/// Used in JetStream, object store and microservice configurations.
final class natsMetadata extends ffi.Struct {
  /// @brief User-provided metadata for the stream, encoded as an array of {"key", "value",...}
  external ffi.Pointer<ffi.Pointer<ffi.Char>> List;

  /// @brief Number of key/value pairs in Metadata, 1/2 of the length of the array.
  @ffi.Int()
  external int Count;
}

final class __jsCtx extends ffi.Opaque {}

/// The JetStream context. Use for JetStream assets management and communication.
///
/// \warning A context MUST not be destroyed concurrently with #jsCtx API calls
/// (for instance #js_Publish or #js_PublishAsync, etc...). However, it
/// is safe to destroy the context while a #jsPubAckErrHandler callback is
/// running or while inside #js_PublishAsyncComplete.
typedef jsCtx = __jsCtx;

/// JetStream publish options.
///
/// These are options that you can provide to JetStream publish APIs.
///
/// The common usage will be to initialize a structure on the stack by
/// calling #jsPubOptions_Init. Note that strings are owned by
/// the application and need to be valid for the duration of the API
/// call this object is passed to.
///
/// \note It is the user responsibility to free the strings if they
/// have been allocated.
///
/// @see jsPubOptions_Init
final class jsPubOptions extends ffi.Struct {
  /// < Amount of time (in milliseconds) to wait for a publish response, default will the context's Wait value.
  @ffi.Int64()
  external int MaxWait;

  /// < Message ID used for de-duplication.
  external ffi.Pointer<ffi.Char> MsgId;

  /// < Expected stream to respond from the publish call.
  external ffi.Pointer<ffi.Char> ExpectStream;

  /// < Expected last message ID in the stream.
  external ffi.Pointer<ffi.Char> ExpectLastMsgId;

  /// < Expected last message sequence in the stream.
  @ffi.Uint64()
  external int ExpectLastSeq;

  /// < Expected last message sequence for the subject in the stream.
  @ffi.Uint64()
  external int ExpectLastSubjectSeq;

  /// < Expected no message (that is, sequence == 0) for the subject in the stream.
  @ffi.Bool()
  external bool ExpectNoMessage;

  /// < Message time to live (TTL) in milliseconds, used by the server to expire the message. Requires nats-server v2.11.0 or later.
  @ffi.Int64()
  external int MsgTTL;
}

/// Determines how messages in a set are retained.
enum jsRetentionPolicy {
  /// < Specifies that messages are retained until any given limit is reached, which could be one of MaxMsgs, MaxBytes, or MaxAge. This is the default.
  js_LimitsPolicy(0),

  /// < Specifies that when all known observables have acknowledged a message it can be removed.
  js_InterestPolicy(1),

  /// < Specifies that when the first worker or subscriber acknowledges the message it can be removed.
  js_WorkQueuePolicy(2);

  final int value;
  const jsRetentionPolicy(this.value);

  static jsRetentionPolicy fromValue(int value) => switch (value) {
        0 => js_LimitsPolicy,
        1 => js_InterestPolicy,
        2 => js_WorkQueuePolicy,
        _ => throw ArgumentError('Unknown value for jsRetentionPolicy: $value'),
      };
}

/// Determines how to proceed when limits of messages or bytes are reached.
enum jsDiscardPolicy {
  /// < Will remove older messages to return to the limits. This is the default.
  js_DiscardOld(0),

  /// < Will fail to store new messages.
  js_DiscardNew(1);

  final int value;
  const jsDiscardPolicy(this.value);

  static jsDiscardPolicy fromValue(int value) => switch (value) {
        0 => js_DiscardOld,
        1 => js_DiscardNew,
        _ => throw ArgumentError('Unknown value for jsDiscardPolicy: $value'),
      };
}

/// Determines how messages are stored for retention.
enum jsStorageType {
  /// < Specifies on disk storage. It's the default.
  js_FileStorage(0),

  /// < Specifies in memory only.
  js_MemoryStorage(1);

  final int value;
  const jsStorageType(this.value);

  static jsStorageType fromValue(int value) => switch (value) {
        0 => js_FileStorage,
        1 => js_MemoryStorage,
        _ => throw ArgumentError('Unknown value for jsStorageType: $value'),
      };
}

/// Determines how messages are compressed when stored for retention.
enum jsStorageCompression {
  /// < Specifies no compression. It's the default.
  js_StorageCompressionNone(0),

  /// < Specifies S2.
  js_StorageCompressionS2(1);

  final int value;
  const jsStorageCompression(this.value);

  static jsStorageCompression fromValue(int value) => switch (value) {
        0 => js_StorageCompressionNone,
        1 => js_StorageCompressionS2,
        _ =>
          throw ArgumentError('Unknown value for jsStorageCompression: $value'),
      };
}

/// Determines how the consumer should select the first message to deliver.
enum jsDeliverPolicy {
  /// < Starts from the very beginning of a stream. This is the default.
  js_DeliverAll(0),

  /// < Starts with the last sequence received.
  js_DeliverLast(1),

  /// < Starts with messages sent after the consumer is created.
  js_DeliverNew(2),

  /// < Starts from a given sequence.
  js_DeliverByStartSequence(3),

  /// < Starts from a given UTC time (number of nanoseconds since epoch)
  js_DeliverByStartTime(4),

  /// < Starts with the last message for all subjects received.
  js_DeliverLastPerSubject(5);

  final int value;
  const jsDeliverPolicy(this.value);

  static jsDeliverPolicy fromValue(int value) => switch (value) {
        0 => js_DeliverAll,
        1 => js_DeliverLast,
        2 => js_DeliverNew,
        3 => js_DeliverByStartSequence,
        4 => js_DeliverByStartTime,
        5 => js_DeliverLastPerSubject,
        _ => throw ArgumentError('Unknown value for jsDeliverPolicy: $value'),
      };
}

/// Determines how the consumer should acknowledge delivered messages.
enum jsAckPolicy {
  /// < Requires ack or nack for all messages.
  js_AckExplicit(0),

  /// < Requires no acks for delivered messages.
  js_AckNone(1),

  /// < When acking a sequence number, this implicitly acks all sequences below this one as well.
  js_AckAll(2);

  final int value;
  const jsAckPolicy(this.value);

  static jsAckPolicy fromValue(int value) => switch (value) {
        0 => js_AckExplicit,
        1 => js_AckNone,
        2 => js_AckAll,
        _ => throw ArgumentError('Unknown value for jsAckPolicy: $value'),
      };
}

/// Determines how the consumer should replay messages it already has queued in the stream.
enum jsReplayPolicy {
  /// < Replays messages as fast as possible.
  js_ReplayInstant(0),

  /// < Maintains the same timing as the messages were received.
  js_ReplayOriginal(1);

  final int value;
  const jsReplayPolicy(this.value);

  static jsReplayPolicy fromValue(int value) => switch (value) {
        0 => js_ReplayInstant,
        1 => js_ReplayOriginal,
        _ => throw ArgumentError('Unknown value for jsReplayPolicy: $value'),
      };
}

/// Used to guide placement of streams in clustered JetStream.
///
/// Initialize the object with #jsPlacement_Init.
///
/// \note The strings are applications owned and will not be freed by the library.
///
/// See #jsStreamConfig for information on how to configure a stream.
///
/// @see jsPlacement_Init
final class jsPlacement extends ffi.Struct {
  external ffi.Pointer<ffi.Char> Cluster;

  external ffi.Pointer<ffi.Pointer<ffi.Char>> Tags;

  @ffi.Int()
  external int TagsLen;
}

/// Allows you to qualify access to a stream source in another account.
///
/// Initialize the object with #jsExternalStream_Init.
///
/// \note The strings are applications owned and will not be freed by the library.
///
/// See #jsStreamConfig for information on how to configure a stream.
final class jsExternalStream extends ffi.Struct {
  external ffi.Pointer<ffi.Char> APIPrefix;

  external ffi.Pointer<ffi.Char> DeliverPrefix;
}

/// Dictates how streams can source from other streams.
///
/// Initialize the object with #jsStreamSource_Init.
///
/// \note The strings are applications owned and will not be freed by the library.
///
/// \note The `OptStartTime` needs to be expressed as the number of nanoseconds
/// passed since 00:00:00 UTC Thursday, 1 January 1970.
///
/// See #jsStreamConfig for information on how to configure a stream.
final class jsStreamSource extends ffi.Struct {
  external ffi.Pointer<ffi.Char> Name;

  @ffi.Uint64()
  external int OptStartSeq;

  /// < UTC time expressed as number of nanoseconds since epoch.
  @ffi.Int64()
  external int OptStartTime;

  external ffi.Pointer<ffi.Char> FilterSubject;

  external ffi.Pointer<jsExternalStream> External;

  /// Domain and External are mutually exclusive.
  /// If Domain is set, an External value will be created with
  /// the APIPrefix constructed based on the Domain value.
  external ffi.Pointer<ffi.Char> Domain;
}

/// Allows a source subject to be mapped to a destination subject for republishing.
final class jsRePublish extends ffi.Struct {
  external ffi.Pointer<ffi.Char> Source;

  external ffi.Pointer<ffi.Char> Destination;

  @ffi.Bool()
  external bool HeadersOnly;
}

/// SubjectTransformConfig is for applying a subject transform (to matching
/// messages) before doing anything else when a new message is received
final class jsSubjectTransformConfig extends ffi.Struct {
  external ffi.Pointer<ffi.Char> Source;

  external ffi.Pointer<ffi.Char> Destination;
}

/// SubjectTransformConfig is for applying a subject transform (to matching
/// messages) before doing anything else when a new message is received
final class jsStreamConsumerLimits extends ffi.Struct {
  @ffi.Int64()
  external int InactiveThreshold;

  @ffi.Int()
  external int MaxAckPending;
}

/// Configuration of a JetStream stream.
///
/// There are sensible defaults for most. If no subjects are
/// given the name will be used as the only subject.
///
/// In order to add/update a stream, a configuration needs to be set.
/// The typical usage would be to initialize all required objects on the stack
/// and configure them, then pass the pointer to the configuration to
/// #js_AddStream or #js_UpdateStream.
///
/// \note The strings are applications owned and will not be freed by the library.
///
/// \note NATS server 2.10 added user-provided Metadata, storage Compression
/// type, FirstSeq to specify the starting sequence number, and SubjectTransform.
///
/// @see jsStreamConfig_Init
///
/// \code{.unparsed}
/// jsStreamConfig   sc;
/// jsPlacement      p;
/// jsStreamSource   m;
/// jsExternalStream esm;
/// jsStreamSource   s1;
/// jsStreamSource   s2;
/// jsExternalStream esmS2;
/// const char       *subjects[]     = {"foo", "bar"};
/// const char       *tags[]         = {"tag1", "tag2"};
/// jsStreamSource   *sources[]      = {&s1, &s2};
/// jsRePublish      rp;
///
/// jsStreamConfig_Init(&sc);
///
/// jsPlacement_Init(&p);
/// p.Cluster = "MyCluster";
/// p.Tags = tags;
/// p.TagsLen = 2;
///
/// jsStreamSource_Init(&m);
/// m.Name = "AStream";
/// m.OptStartSeq = 100;
/// m.FilterSubject = "foo";
/// jsExternalStream_Init(&esm);
/// esm.APIPrefix = "mirror.prefix.";
/// esm.DeliverPrefix = "deliver.prefix.";
/// m.External = &esm;
///
/// jsStreamSource_Init(&s1);
/// s1.Name = "StreamOne";
/// s1.OptStartSeq = 10;
/// s1.FilterSubject = "stream.one";
///
/// jsStreamSource_Init(&s2);
/// s2.Name = "StreamTwo";
/// s2.FilterSubject = "stream.two";
/// jsExternalStream_Init(&esmS2);
/// esmS2.APIPrefix = "mirror.prefix.";
/// esmS2.DeliverPrefix = "deliver.prefix.";
/// s2.External = &esmS2;
///
/// sc.Name = "MyStream";
/// sc.Subjects = subjects;
/// sc.SubjectsLen = 2;
/// sc.Retention = js_InterestPolicy;
/// sc.Replicas = 3;
/// sc.Placement = &p;
/// sc.Mirror = &m;
/// sc.Sources = sources;
/// sc.SourcesLen = 2;
///
/// // For RePublish subject:
/// jsRePublish_Init(&rp);
/// rp.Source = ">";
/// rp.Destination = "RP.>";
/// sc.RePublish = &rp;
///
/// s = js_AddStream(&si, js, &sc, NULL, &jerr);
/// \endcode
final class jsStreamConfig extends ffi.Struct {
  external ffi.Pointer<ffi.Char> Name;

  external ffi.Pointer<ffi.Char> Description;

  external ffi.Pointer<ffi.Pointer<ffi.Char>> Subjects;

  @ffi.Int()
  external int SubjectsLen;

  @ffi.UnsignedInt()
  external int RetentionAsInt;

  jsRetentionPolicy get Retention =>
      jsRetentionPolicy.fromValue(RetentionAsInt);

  @ffi.Int64()
  external int MaxConsumers;

  @ffi.Int64()
  external int MaxMsgs;

  @ffi.Int64()
  external int MaxBytes;

  /// < Max age of messages in nanoseconds.
  @ffi.Int64()
  external int MaxAge;

  @ffi.Int64()
  external int MaxMsgsPerSubject;

  @ffi.Int32()
  external int MaxMsgSize;

  @ffi.UnsignedInt()
  external int DiscardAsInt;

  jsDiscardPolicy get Discard => jsDiscardPolicy.fromValue(DiscardAsInt);

  @ffi.UnsignedInt()
  external int StorageAsInt;

  jsStorageType get Storage => jsStorageType.fromValue(StorageAsInt);

  @ffi.Int64()
  external int Replicas;

  @ffi.Bool()
  external bool NoAck;

  external ffi.Pointer<ffi.Char> Template;

  @ffi.Int64()
  external int Duplicates;

  external ffi.Pointer<jsPlacement> Placement;

  external ffi.Pointer<jsStreamSource> Mirror;

  external ffi.Pointer<ffi.Pointer<jsStreamSource>> Sources;

  @ffi.Int()
  external int SourcesLen;

  /// < Seal a stream so no messages can get our or in.
  @ffi.Bool()
  external bool Sealed;

  /// < Restrict the ability to delete messages.
  @ffi.Bool()
  external bool DenyDelete;

  /// < Restrict the ability to purge messages.
  @ffi.Bool()
  external bool DenyPurge;

  /// @brief Allow messages to be placed into the system and purge all
  /// older messages using a special message header.
  @ffi.Bool()
  external bool AllowRollup;

  /// @brief Allow republish of the message after being sequenced and
  /// stored.
  external ffi.Pointer<jsRePublish> RePublish;

  /// @brief Allow higher performance, direct access to get individual
  /// messages. E.g. KeyValue
  @ffi.Bool()
  external bool AllowDirect;

  /// @brief Allow higher performance and unified direct access for
  /// mirrors as well.
  @ffi.Bool()
  external bool MirrorDirect;

  /// @brief Allow KV like semantics to also discard new on a per subject
  /// basis
  @ffi.Bool()
  external bool DiscardNewPerSubject;

  /// @brief A user-provided array of key/value pairs, encoded as a string
  /// array [n1, v1, n2, v2, ...] representing key/value pairs {n1:v1,
  /// n2:v2, ...}.
  external natsMetadata Metadata;

  /// @brief js_StorageCompressionNone (default) or
  /// js_StorageCompressionS2.
  @ffi.UnsignedInt()
  external int CompressionAsInt;

  jsStorageCompression get Compression =>
      jsStorageCompression.fromValue(CompressionAsInt);

  /// @brief  the starting sequence number for the stream.
  @ffi.Uint64()
  external int FirstSeq;

  /// @brief Applies a subject transform (to matching messages) before
  /// doing anything else when a new message is received.
  external jsSubjectTransformConfig SubjectTransform;

  /// @brief Sets the limits on certain options on all consumers of the
  /// stream.
  external jsStreamConsumerLimits ConsumerLimits;

  /// @brief Allow the message to be sent with a time to live (TTL) value.
  /// Requires nats-server v2.11.0 or later.
  @ffi.Bool()
  external bool AllowMsgTTL;

  /// @brief Enables and sets a duration for adding server markers for
  /// delete, purge and max age limits. In nanoseconds. Requires
  /// nats-server v2.11.0 or later.
  @ffi.Int64()
  external int SubjectDeleteMarkerTTL;
}

/// Information about messages that have been lost
final class jsLostStreamData extends ffi.Struct {
  external ffi.Pointer<ffi.Uint64> Msgs;

  @ffi.Int()
