/// Configuration of a JetStream consumer.
///
/// In order to add a consumer, a configuration needs to be set.
/// The typical usage would be to initialize all required objects on the stack
/// and configure them, then pass the pointer to the configuration to
/// #js_AddConsumer.
///
/// \note `OptStartTime` needs to be expressed as the number of nanoseconds
/// passed since 00:00:00 UTC Thursday, 1 January 1970.
///
/// \note The strings are applications owned and will not be freed by the library.
///
/// \note `SampleFrequency` is a sampling value, represented as a string such as "50"
/// for 50%, that causes the server to produce advisories for consumer ack metrics.
///
/// \note `Durable` cannot contain the character ".".
///
/// \note `HeadersOnly` means that the subscription will not receive any message payload,
/// instead, it will receive only messages headers (if present) with the addition of
/// the header #JSMsgSize ("Nats-Msg-Size"), whose value is the payload size.
///
/// \note NATS server 2.10 added FilterSubjects, an array of multiple filter
/// subjects. It is mutually exclusive with the previously available single
/// FilterSubject.
///
/// \note NATS server 2.10 added consumer Metadata which contains user-provided
/// string name/value pairs.
///
/// @see jsConsumerConfig_Init
///
/// \code{.unparsed}
/// jsConsumerInfo   *ci = NULL;
/// jsConsumerConfig cc;
///
/// jsConsumerConfig_Init(&cc);
/// cc.Durable = "MY_DURABLE";
/// cc.DeliverSubject = "foo";
/// cc.DeliverPolicy = js_DeliverNew;
///
/// s = js_AddConsumer(&ci, js, &cc, NULL, &jerr);
/// \endcode
final class jsConsumerConfig extends ffi.Struct {
  external ffi.Pointer<ffi.Char> Name;

  external ffi.Pointer<ffi.Char> Durable;

  external ffi.Pointer<ffi.Char> Description;

  @ffi.UnsignedInt()
  external int DeliverPolicyAsInt;

  jsDeliverPolicy get DeliverPolicy =>
      jsDeliverPolicy.fromValue(DeliverPolicyAsInt);

  @ffi.Uint64()
  external int OptStartSeq;

  /// < UTC time expressed as number of nanoseconds since epoch.
  @ffi.Int64()
  external int OptStartTime;

  @ffi.UnsignedInt()
  external int AckPolicyAsInt;

  jsAckPolicy get AckPolicy => jsAckPolicy.fromValue(AckPolicyAsInt);

  @ffi.Int64()
  external int AckWait;

  @ffi.Int64()
  external int MaxDeliver;

  /// < Redelivery durations expressed in nanoseconds
  external ffi.Pointer<ffi.Int64> BackOff;

  @ffi.Int()
  external int BackOffLen;

  external ffi.Pointer<ffi.Char> FilterSubject;

  @ffi.UnsignedInt()
  external int ReplayPolicyAsInt;

  jsReplayPolicy get ReplayPolicy =>
      jsReplayPolicy.fromValue(ReplayPolicyAsInt);

  @ffi.Uint64()
  external int RateLimit;

  external ffi.Pointer<ffi.Char> SampleFrequency;

  @ffi.Int64()
  external int MaxWaiting;

  @ffi.Int64()
  external int MaxAckPending;

  @ffi.Bool()
  external bool FlowControl;

  /// < Heartbeat interval expressed in number of nanoseconds.
  @ffi.Int64()
  external int Heartbeat;

  @ffi.Bool()
  external bool HeadersOnly;

  /// < Maximum Pull Consumer request batch size.
  @ffi.Int64()
  external int MaxRequestBatch;

  /// < Maximum Pull Consumer request expiration, expressed in number of nanoseconds.
  @ffi.Int64()
  external int MaxRequestExpires;

  /// < Maximum Pull Consumer request maximum bytes.
  @ffi.Int64()
  external int MaxRequestMaxBytes;

  /// Push based options.
  external ffi.Pointer<ffi.Char> DeliverSubject;

  external ffi.Pointer<ffi.Char> DeliverGroup;

  /// < How long the server keeps an ephemeral after detecting loss of interest, expressed in number of nanoseconds.
  @ffi.Int64()
  external int InactiveThreshold;

  /// Generally inherited by parent stream and other markers, now can be configured directly.
  @ffi.Int64()
  external int Replicas;

  /// Force memory storage.
  @ffi.Bool()
  external bool MemoryStorage;

  /// < Multiple filter subjects
  external ffi.Pointer<ffi.Pointer<ffi.Char>> FilterSubjects;

  @ffi.Int()
  external int FilterSubjectsLen;

  /// < User-provided metadata for the consumer, encoded as an array of {"key", "value",...}
  external natsMetadata Metadata;

  /// \brief Suspends the consumer until this deadline, represented as
  /// number of nanoseconds since epoch. Requires nats-server v2.11.0 or
  /// later.
  @ffi.Int64()
  external int PauseUntil;

  /// \brief Represents he priority policy the consumer is set to. Must be
  /// "pinned_client" or "overflow". Requires nats-server v2.11.0 or
  /// later.
  external ffi.Pointer<ffi.Char> PriorityPolicy;

  /// \brief PinnedTTL represents the time after which the client will be
  /// unpinned if no new pull requests are sent. Used with
  /// PriorityPolicyPinned. Expressed in nanoseconds. Requires nats-server
  /// v2.11.0 or later.
  @ffi.Int64()
  external int PinnedTTL;

  /// \brief The list of priority groups this consumer supports.
  external ffi.Pointer<ffi.Pointer<ffi.Char>> PriorityGroups;

  @ffi.Int()
  external int PriorityGroupsLen;
}

/// This represents a consumer sequence mismatch between the server and client
/// views.
///
/// This can help applications find out if messages have been missed. Without
/// this and during a disconnect, it would be possible that a subscription
/// is not aware that it missed messages from the server. When acknowledgment
/// mode is other than #js_AckNone, messages would ultimately be redelivered,
/// but for #js_AckNone, they would not. But even with an acknowledgment mode
/// this may help finding sooner that something went wrong and let the application
/// decide if it wants to recreate the subscription starting at a given
/// sequence.
///
/// The gap of missing messages could be calculated as `ConsumerServer-ConsumerClient`.
///
/// @see natsSubscription_GetSequenceMismatch
final class jsConsumerSequenceMismatch extends ffi.Struct {
  /// < This is the stream sequence that the application should resume from.
  @ffi.Uint64()
  external int Stream;

  /// < This is the consumer sequence that was last received by the library.
  @ffi.Uint64()
  external int ConsumerClient;

  /// < This is the consumer sequence last sent by the server.
  @ffi.Uint64()
  external int ConsumerServer;
}

/// JetStream subscribe options.
///
/// These are options that you can provide to JetStream subscribe APIs.
///
/// The common usage will be to initialize a structure on the stack by
/// calling #jsSubOptions_Init. Note that strings are owned by
/// the application and need to be valid for the duration of the API
/// call this object is passed to.
///
/// \note It is the user responsibility to free the strings if they
/// have been allocated.
///
/// @see jsSubOptions_Init
final class jsSubOptions extends ffi.Struct {
  /// < If specified, the consumer will be bound to this stream name.
  external ffi.Pointer<ffi.Char> Stream;

  /// < If specified, the subscription will be bound to an existing consumer from the `Stream` without attempting to create.
  external ffi.Pointer<ffi.Char> Consumer;

  /// < Queue name for queue subscriptions.
  external ffi.Pointer<ffi.Char> Queue;

  /// < If true, the user will have to acknowledge the messages.
  @ffi.Bool()
  external bool ManualAck;

  /// < Consumer configuration.
  external jsConsumerConfig Config;

  /// < If true, this will be an ordered consumer.
  @ffi.Bool()
  external bool Ordered;
}

