final class jsFetchRequest extends ffi.Struct {
  /// < Expiration of the request, expressed in nanoseconds
  @ffi.Int64()
  external int Expires;

  /// < Maximum number of messages to be received (see MaxBytes)
  @ffi.Int()
  external int Batch;

  /// < Maximum bytes for the request (request complete based on whichever Batch or MaxBytes comes first)
  @ffi.Int64()
  external int MaxBytes;

  /// < Will not wait if the request cannot be completed
  @ffi.Bool()
  external bool NoWait;

  /// < Have server sends heartbeats to help detect communication failures
  @ffi.Int64()
  external int Heartbeat;

  /// The use of these  fields require nats-server v2.11.0 or later
  @ffi.Int64()
  external int MinPending;

  @ffi.Int64()
  external int MinAckPending;

  /// < the "pinned" ID of this subscription, if any; to use with the
  external ffi.Pointer<ffi.Char> ID;

  /// "pinned_client" priority policy
  external ffi.Pointer<ffi.Char> Group;
}

typedef jsFetchCompleteHandlerFunction = ffi.Void Function(
    ffi.Pointer<natsConnection> nc,
    ffi.Pointer<natsSubscription> sub,
    ffi.UnsignedInt s,
    ffi.Pointer<ffi.Void> closure);
typedef DartjsFetchCompleteHandlerFunction = void Function(
    ffi.Pointer<natsConnection> nc,
    ffi.Pointer<natsSubscription> sub,
    natsStatus s,
    ffi.Pointer<ffi.Void> closure);

/// \brief Callback used to indicate that the work of js_PullSubscribeAsync is
/// done.
///
/// @param nc - Connection to the NATS server
/// @param sub - Subscription being used
/// @param s - Completion status code
/// - `NATS_OK` - should never happen here!
/// - `NATS_TIMEOUT` indicates that the fetch has reached its lifetime expiration
/// time, or had NoWait set and there are no more messages.
/// - `NATS_NOT_FOUND` is returned when the server has no messages to deliver at
/// the beginning of a specific request. It may be returned for NoWait
/// subscriptions, effectively the same meaning as NATS_TIMEOUT - early
/// termination for NoWait.
/// - `NATS_MAX_DELIVERED_MSGS` indicates that lifetime `Batch` message limit has
/// been reached.
/// - `NATS_LIMIT_REACHED` is returned when the lifetime byte limit is reached.
/// - Other status values represent error conditions.
/// @param closure completeClosure that was passed to js_PullSubscribeAsync
///
/// @see js_PullSubscribeAsync
typedef jsFetchCompleteHandler
    = ffi.Pointer<ffi.NativeFunction<jsFetchCompleteHandlerFunction>>;
typedef jsFetchNextHandlerFunction = ffi.Bool Function(
    ffi.Pointer<ffi.Int> messages,
    ffi.Pointer<ffi.Int64> maxBytes,
    ffi.Pointer<natsSubscription> sub,
    ffi.Pointer<ffi.Void> closure);
typedef DartjsFetchNextHandlerFunction = bool Function(
    ffi.Pointer<ffi.Int> messages,
    ffi.Pointer<ffi.Int64> maxBytes,
    ffi.Pointer<natsSubscription> sub,
    ffi.Pointer<ffi.Void> closure);

/// \brief Callback used to customize flow control for js_PullSubscribeAsync.
///
/// The library will invoke this callback when it may be time to request more
/// messages from the server.
///
/// @return true to fetch more, false to skip. If true, \p messages and \p
/// maxBytes should be set to the number of messages and max bytes to fetch.
///
/// @see js_PullSubscribeAsync
typedef jsFetchNextHandler
    = ffi.Pointer<ffi.NativeFunction<jsFetchNextHandlerFunction>>;

/// Async pull subscriber options.
///
/// Part of #jsOptions.
final class jsOptionsPullSubscribeAsync extends ffi.Struct {
  /// < Auto-unsubsribe after this many milliseconds.
  @ffi.Int64()
  external int Timeout;

  /// < Auto-unsubscribed after receiving this many messages.
  @ffi.Int()
  external int MaxMessages;

  /// < Auto-unsubscribe after receiving this many bytes.
  @ffi.Int64()
  external int MaxBytes;

  /// \brief If NoWait is set, the subscription will receive the
  /// messages already stored on the server subject to the limits,
  /// but will not wait for more messages.
  ///
  /// \note that if Timeout is set we would still wait for first
  /// message to become available, even if there are currently any
  /// on the server
  @ffi.Bool()
  external bool NoWait;

  /// \brief Fetch complete handler that receives the exit status
  /// code, the subscription's Complete handler is also invoked,
  /// but does not have the status code.
  external jsFetchCompleteHandler CompleteHandler;

  external ffi.Pointer<ffi.Void> CompleteHandlerClosure;

  /// \brief Have server sends heartbeats at this interval (in
  /// milliseconds) to help detect communication failures.
  @ffi.Int64()
  external int Heartbeat;

  /// @brief The name of consumer priority group.
  ///
  /// @note The use of this option require nats-server v2.11.0 or later,
  /// and a consumer with priority groups enabled and configured.
  external ffi.Pointer<ffi.Char> Group;

  /// @brief When specified, this subscription will only receive messages
  /// when the consumer has at least this many pending messages.
  ///
  /// @note The use of this option require nats-server v2.11.0 or later,
  /// and a consumer with priority groups enabled and configured.
  @ffi.Int64()
  external int MinPending;

  /// @brief When specified, this Pull request will only receive messages
  /// when the consumer has at least this many ack pending messages.
  ///
  /// @note The use of this option require nats-server v2.11.0 or later,
  /// and a consumer with priority groups enabled and configured.
  @ffi.Int64()
  external int MinAckPending;

  /// @brief When using the automatic Fetch flow control (default
  /// NextHandler), this is the number of messages to ask for in a
  /// single request.
  @ffi.Int()
  external int FetchSize;

  /// @brief When using the automatic Fetch flow control (default
  /// NextHandler), initiate the next fetch request (this many
  /// messages) prior to the fulfillment of the current request.
  ///
  /// @note KeepAhead can not be used in conjunction with MaxBytes
  /// or NoWait.
  @ffi.Int()
  external int KeepAhead;

  /// @brief If set, switches to manual fetch flow control.
  ///
  /// If provided, this function gets called before each message
  /// is deliverered to msgCB, and overrides the default algorithm
  /// for sending Next fetch requests.
  external jsFetchNextHandler NextHandler;

  external ffi.Pointer<ffi.Void> NextHandlerClosure;
}

/// Async pull options.
///
/// Part of #jsOptions.
final class jsOptionsPublishAsync extends ffi.Struct {
  /// < Maximum outstanding asynchronous publishes that can be inflight at one time.
  @ffi.Int64()
  external int MaxPending;

  /// < Callback invoked for each asynchronous published message.
  external jsPubAckHandler AckHandler;

  /// < Closure (or user data) passed to #jsPubAckHandler callback.
  external ffi.Pointer<ffi.Void> AckHandlerClosure;

  /// < Callback invoked when error encountered publishing a given message.
  external jsPubAckErrHandler ErrHandler;

  /// < Closure (or user data) passed to #jsPubAckErrHandler callback.
  external ffi.Pointer<ffi.Void> ErrHandlerClosure;

  /// < Amount of time (in milliseconds) to wait in a PublishAsync call when there is MaxPending inflight messages, default is 200 ms.
  @ffi.Int64()
  external int StallWait;
}

/// Advanced stream purge options
///
/// * `Subject` will filter the purge request to only messages that match the subject, which can have wildcards.<br>
/// * `Sequence` will purge up to but not including this sequence and can be combined with subject filtering.<br>
/// * `Keep` will specify how many messages to keep and can be combined with subject filtering.<br>
///
/// \note `Sequence` and `Keep` are mutually exclusive, so both can not be set at the same time.
final class jsOptionsStreamPurge extends ffi.Struct {
  /// < This is the subject to match against messages for the purge command.
  external ffi.Pointer<ffi.Char> Subject;

  /// < Purge up to but not including sequence.
  @ffi.Uint64()
  external int Sequence;

  /// < Number of messages to keep.
  @ffi.Uint64()
  external int Keep;
}

/// Advance stream information retrieval options
final class jsOptionsStreamInfo extends ffi.Struct {
  /// < Get the list of deleted message sequences.
  @ffi.Bool()
  external bool DeletedDetails;

  /// < Get the list of subjects in this stream.
  external ffi.Pointer<ffi.Char> SubjectsFilter;
}

/// Advanced stream options
///
/// * `Purge` for advanced purge options.
/// * `Info` for advanced information retrieval options.
final class jsOptionsStream extends ffi.Struct {
  /// < Optional stream purge options.
  external jsOptionsStreamPurge Purge;

  /// < Optional stream information retrieval options.
  external jsOptionsStreamInfo Info;
}

/// JetStream context options.
///
/// Initialize the object with #jsOptions_Init.
final class jsOptions extends ffi.Struct {
  /// < JetStream prefix, default is "$JS.API"
  external ffi.Pointer<ffi.Char> Prefix;

  /// < Domain changes the domain part of JetSteam API prefix.
  external ffi.Pointer<ffi.Char> Domain;

  /// < Amount of time (in milliseconds) to wait for various JetStream API requests, default is 5000 ms (5 seconds).
  @ffi.Int64()
  external int Wait;

  /// < extra options for #js_PublishAsync
  external jsOptionsPublishAsync PublishAsync;

  /// < extra options for #js_PullSubscribeAsync
  external jsOptionsPullSubscribeAsync PullSubscribeAsync;

  /// < Optional stream options.
  external jsOptionsStream Stream;
}

final class __kvStore extends ffi.Opaque {}

/// The KeyValue store object.
typedef kvStore = __kvStore;

final class __kvEntry extends ffi.Opaque {}

/// The KeyValue entry object.
typedef kvEntry = __kvEntry;

final class __kvStatus extends ffi.Opaque {}

/// The KeyValue status object.
typedef kvStatus = __kvStatus;

final class __kvWatcher extends ffi.Opaque {}

/// The KeyValue watcher object.
typedef kvWatcher = __kvWatcher;

/// Determines the type of operation of a #kvEntry
enum kvOperation {
  kvOp_Unknown(0),
  kvOp_Put(1),
  kvOp_Delete(2),
  kvOp_Purge(3);

  final int value;
  const kvOperation(this.value);

  static kvOperation fromValue(int value) => switch (value) {
        0 => kvOp_Unknown,
        1 => kvOp_Put,
        2 => kvOp_Delete,
        3 => kvOp_Purge,
        _ => throw ArgumentError('Unknown value for kvOperation: $value'),
      };
}

/// KeyValue configuration object.
///
/// Initialize the object with #kvConfig_Init.
final class kvConfig extends ffi.Struct {
  external ffi.Pointer<ffi.Char> Bucket;

  external ffi.Pointer<ffi.Char> Description;

  @ffi.Int32()
  external int MaxValueSize;

  @ffi.Uint8()
  external int History;

  @ffi.Int64()
  external int TTL;

  @ffi.Int64()
  external int MaxBytes;

  @ffi.UnsignedInt()
  external int StorageTypeAsInt;

  jsStorageType get StorageType => jsStorageType.fromValue(StorageTypeAsInt);

  @ffi.Int()
  external int Replicas;

  external ffi.Pointer<jsRePublish> RePublish;

  external ffi.Pointer<jsStreamSource> Mirror;

  external ffi.Pointer<ffi.Pointer<jsStreamSource>> Sources;

  @ffi.Int()
  external int SourcesLen;
}

/// KeyValue watcher options object.
///
/// Initialize the object with #kvWatchOptions_Init
final class kvWatchOptions extends ffi.Struct {
  @ffi.Bool()
  external bool IgnoreDeletes;

  @ffi.Bool()
  external bool IncludeHistory;

  @ffi.Bool()
  external bool MetaOnly;

  /// < How long to wait (in milliseconds) for some operations to complete.
  @ffi.Int64()
  external int Timeout;

  /// < Only receive updates, no initial snapshot.
  @ffi.Bool()
  external bool UpdatesOnly;
}

/// KeyValue purge options object.
///
/// Initialize the object with #kvPurgeOptions_Init
final class kvPurgeOptions extends ffi.Struct {
  /// How long to wait (in milliseconds) for some operations to complete.
  @ffi.Int64()
  external int Timeout;

  /// When calling kvStore_PurgeDeletes(), all keys that have a delete or
  /// purge marker as the last entry are gathered and then those keys
  /// are purged of their content, including the marker.
  /// Starting with NATS C client v3.3.0, if this option is not specified,
  /// only the markers older than 30 minutes will be deleted. Use this
  /// option to set the limit or a negative value to force removal of
  /// markers regardless of their age.
  /// The value is expressed as a time in nanoseconds.
  @ffi.Int64()
  external int DeleteMarkersOlderThan;
}

/// \brief A list of KeyValue store entries.
///
/// Used by some APIs which return a list of #kvEntry objects.
///
/// Those APIs will not create the object, but instead initialize
/// the object.
///
/// Typically, the user will define the object on the stack and
/// pass a pointer to this object to APIs that require a pointer
/// to a #kvEntryList object.
///
/// Similarly, calling #kvEntryList_Destroy will call #kvEntry_Destroy
/// on entries in the list, free the array containing pointers
/// to the entries, but not free the #kvEntryList object itself.
///
/// @see kvEntryList_Destroy
final class kvEntryList extends ffi.Struct {
  external ffi.Pointer<ffi.Pointer<kvEntry>> Entries;

  @ffi.Int()
  external int Count;
}

/// \brief A list of KeyValue store keys.
///
/// Used by some APIs which return a list of key names.
///
/// Those APIs will not create the object, but instead initialize
/// the object.
///
/// Typically, the user will define the object on the stack and
/// pass a pointer to this object to APIs that require a pointer
/// to a #kvKeysList object.
///
/// Similarly, calling #kvKeysList_Destroy will free key strings
/// in the list, free the array containing pointers to the keys,
/// but not free the #kvKeysList object itself.
///
/// @see kvKeysList_Cleanup
final class kvKeysList extends ffi.Struct {
  external ffi.Pointer<ffi.Pointer<ffi.Char>> Keys;

  @ffi.Int()
  external int Count;
}

/// \brief Callback used to deliver messages to the application.
///
/// This is the callback that one provides when creating an asynchronous
/// subscription. The library will invoke this callback for each message
/// arriving through the subscription's connection.
///
/// \warning If this callback is setup for a subject that is used as the reply
/// subject to #natsConnection_PublishRequest calls (and its variants), it
/// is possible to get an empty message with a header "Status" with value
/// "503" that is sent by the server when there were no responders on the
/// request's subject. Use #natsMsg_IsNoResponders to know if that is the case.
///
/// @see natsConnection_Subscribe()
/// @see natsConnection_QueueSubscribe()
/// @see natsMsg_IsNoResponders()
typedef natsMsgHandler = ffi.Pointer<
    ffi.NativeFunction<
        ffi.Void Function(
            ffi.Pointer<natsConnection> nc,
            ffi.Pointer<natsSubscription> sub,
            ffi.Pointer<natsMsg> msg,
            ffi.Pointer<ffi.Void> closure)>>;

/// \brief Callback used to notify the user of asynchronous connection events.
///
/// This callback is used for asynchronous events such as disconnected
/// and closed connections.
///
/// @see natsOptions_SetClosedCB()
/// @see natsOptions_SetDisconnectedCB()
/// @see natsOptions_SetReconnectedCB()
///
/// \warning Such callback is invoked from a dedicated thread and the state
/// of the connection that triggered the event may have changed since
/// that event was generated.
typedef natsConnectionHandler = ffi.Pointer<
    ffi.NativeFunction<
        ffi.Void Function(
            ffi.Pointer<natsConnection> nc, ffi.Pointer<ffi.Void> closure)>>;

/// \brief Callback used to notify the user of errors encountered while processing
/// inbound messages.
///
/// This callback is used to process asynchronous errors encountered while processing
/// inbound messages, such as #NATS_SLOW_CONSUMER.
typedef natsErrHandler = ffi.Pointer<
    ffi.NativeFunction<
        ffi.Void Function(
            ffi.Pointer<natsConnection> nc,
            ffi.Pointer<natsSubscription> subscription,
            ffi.UnsignedInt err,
            ffi.Pointer<ffi.Void> closure)>>;

const String NATS_DEFAULT_URL = 'nats://localhost:4222';
